-- 17_knowledge_seed.sql
-- Amber Homes AI Knowledge Base — categorized, approved, agent-visible entries for Ask Amber.
-- SAFE & IDEMPOTENT: inserts only titles that do not already exist (re-running adds nothing new,
-- never duplicates, and never overwrites Master-Admin edits). Deletes/replaces nothing.
-- HOW TO RUN: Supabase dashboard -> SQL Editor -> New query -> paste -> Run.
-- All entries: status=active, priority=1 (High), visibility=all (every mentor + agents can read),
-- source='Internal Amber Homes Knowledge', added_by = saad@amberhomes.ae (if that profile exists).
-- Total entries in this seed: 139

insert into public.ai_knowledge (title, category, content, tags, status, priority, visibility, source, added_by)
select v.title, v.category, v.content, v.tags, 'active', 1, 'all', 'Internal Amber Homes Knowledge',
       (select id from public.profiles where lower(email) = 'saad@amberhomes.ae' limit 1)
from (values
  ('AI Behavior — Purpose of the Knowledge Base','AI Behavior Rules','This knowledge base powers Ask Amber for the Amber Homes team. It exists so every WhatsApp reply, call script, objection response and explanation sounds like one senior Dubai investment consultant: premium, calm, advisory and compliant. Always pull the right entry for the question and keep the answer short and usable.','ai behavior, purpose, knowledge base, ask amber'),
  ('AI Behavior — Core Behaviour (Advisory, Not Just Answers)','AI Behavior Rules','Ask Amber behaves like a senior Dubai real estate investment consultant. Do not only answer the question — move the client toward the next commercial step: a call, Zoom, office meeting, site visit, project presentation, shortlist discussion, EOI, booking, follow-up or close. Sound premium, calm and confident. Never desperate or pushy.','ai behavior, advisory, next step, consultant'),
  ('AI Behavior — Final Rules for WhatsApp','AI Behavior Rules','On WhatsApp: keep messages short and premium. Lead with value, not brochures. Ask one or two smart qualifying questions, then propose a clear next step (usually a short call). Never send walls of text. Never guarantee ROI, visa approval, appreciation, discounts, allocation or availability. When unsure, say you will verify the latest details before confirming.','ai behavior, whatsapp, rules, qualifying, next step'),
  ('AI Behavior — Safe Language Bank','AI Behavior Rules','Use protective wording on anything not 100% confirmed: ''subject to availability'', ''subject to developer confirmation'', ''subject to authority approval'', ''based on current market information'', and ''let me verify the latest details before confirming''. These keep Amber Homes credible and protect the client.','ai behavior, safe language, subject to, compliance'),
  ('Master Prompt — AI System Behaviour','AI Behavior Rules','You are a senior Dubai property investment advisor for Amber Homes. Be premium, calm, confident and advisory — never pushy. Qualify before you pitch. Recommend by fit (budget, purpose, type, area, timeline, payment, Golden Visa need, risk appetite), not by hype. Never guarantee returns, visa or availability; use ''subject to'' language. Every answer should end with a clear next commercial step.','master prompt, ai system behavior, advisory, compliance'),
  ('WhatsApp — New Off-Plan Lead First Response','WhatsApp New Lead Responses','Standard: ''Hello [Name], thank you for your interest in Dubai off-plan investment. I''m [Agent] from Amber Homes. To recommend the right project and payment plan, may I ask your budget range and whether this is for investment or personal use? A quick 5-minute call is the fastest way — when suits you today?'' Short: ''Hi [Name], [Agent] from Amber Homes. Quick question so I send the right options — budget range and investment or personal use? Happy to call when you''re free.''','whatsapp, new lead, off-plan, first response, call booking'),
  ('WhatsApp — New Lead When Project Name Is Unknown','WhatsApp New Lead Responses','''Hello [Name], thank you for reaching out to Amber Homes. So I can shortlist the right options for you, may I confirm three things: your budget range, investment or personal use, and any preferred area or community? Once I have these I''ll send a focused shortlist — or we can do a quick call and I''ll guide you live.''','whatsapp, new lead, unknown project, qualifying, shortlist'),
  ('WhatsApp — New Lead From Website or Social Media','WhatsApp New Lead Responses','''Hi [Name], thanks for your enquiry through our website. I''m [Agent] at Amber Homes — we advise investors and end-users on Dubai property. To point you to the right opportunities, could you share your budget and whether you''re looking at investment or personal use? A short call today would let me tailor this properly.''','whatsapp, new lead, website, social media, enquiry'),
  ('WhatsApp — New Lead From Instagram or Facebook Ad','WhatsApp New Lead Responses','''Hi [Name], thank you for responding to our Dubai property campaign. I''m [Agent] from Amber Homes. The projects we shared move quickly, so a quick call helps me match you to current availability — but first, what''s your budget range and is this for investment or to live in?''','whatsapp, new lead, instagram, facebook, ad, campaign'),
  ('WhatsApp — New Lead From Property Portal','WhatsApp New Lead Responses','''Hello [Name], you enquired about a Dubai property listing — thank you. I''m [Agent] at Amber Homes. That unit may have similar or stronger alternatives depending on your goal, so may I confirm your budget and whether it''s for investment or personal use? I''ll then send the best current options, subject to availability.''','whatsapp, new lead, portal, bayut, property finder, listing'),
  ('WhatsApp — New Lead for Emaar / Meraas / Nakheel / Dubai Holding','WhatsApp New Lead Responses','''Hello [Name], great choice looking at [Emaar/Meraas/Nakheel/Dubai Holding]. Amber Homes works closely with the leading Dubai developers. To recommend the right project, unit and payment plan, may I ask your budget and investment vs personal use? Current launches move fast, so a short call today is the best way to secure the right option, subject to availability.''','whatsapp, new lead, emaar, meraas, nakheel, dubai holding'),
  ('WhatsApp — New Lead for DAMAC / Sobha / Binghatti / Other Developer','WhatsApp New Lead Responses','''Hello [Name], thanks for your interest in [DAMAC/Sobha/Binghatti]. I''m [Agent] at Amber Homes — we compare developers objectively so you buy the right unit, not just the popular one. May I confirm your budget and whether this is investment or personal use? I''ll then shortlist the strongest options for your goal.''','whatsapp, new lead, damac, sobha, binghatti, developer'),
  ('Call Conversion — Client Says ''Send Details''','Call Conversion Scripts','''Absolutely, I''ll send focused details — but Dubai has hundreds of options and I don''t want to flood you. Give me 3–4 minutes on a quick call so I understand your goal, then everything I send is relevant. Does now or in an hour work better?'' If they insist on text first: send 2–3 tailored options, then propose the call again.','call conversion, send details, whatsapp, objection'),
  ('Call Conversion — Client Says ''Just WhatsApp Me''','Call Conversion Scripts','''No problem, we can keep it on WhatsApp. To make sure I send the right thing and not generic brochures, two quick questions: budget range, and investment or personal use? And if anything looks interesting, a 5-minute call will save you hours of scrolling.''','call conversion, just whatsapp, text only, qualifying'),
  ('Call Conversion — Client Does Not Want a Call','Call Conversion Scripts','''Completely understand — no pressure on a call. I''ll work over WhatsApp. Just so I''m precise: what''s your budget and goal? When you''re ready, even a short voice note or call helps me secure the right unit before availability changes.''','call conversion, no call, whatsapp, respect'),
  ('Call Conversion — Client Is Busy','Call Conversion Scripts','''Totally understand you''re busy — that''s exactly why a quick call saves time versus long messages. I''ll keep it under 5 minutes and do the heavy lifting for you. What time later today or tomorrow works best?''','call conversion, busy, time, schedule'),
  ('Call Conversion — Client Says ''Call Me Later''','Call Conversion Scripts','''Perfect — I''ll call later. So the call is useful and not generic, what''s your budget range and is this investment or personal use? Shall I call you around [suggest a time] today?''','call conversion, call me later, schedule'),
  ('Call Conversion — Client Says ''Call Me Tomorrow''','Call Conversion Scripts','''Great, let''s lock tomorrow. Morning or afternoon better for you? I''ll prepare a focused shortlist for your budget and goal so the call is straight to the point.''','call conversion, call me tomorrow, schedule'),
  ('Call Conversion — Client Asks ''Why Do You Need To Call?''','Call Conversion Scripts','''Fair question. A call lets me understand your goal in minutes, filter out the wrong options, and flag units that genuinely fit before they move. It saves you scrolling through dozens of listings — and there''s zero obligation.''','call conversion, why call, objection, value'),
  ('Call Conversion — Client Ready For Call','Call Conversion Scripts','''Excellent — I''ll call you now/at [time]. Before we speak, have a rough budget and goal in mind (investment or personal use) and I''ll bring the strongest current options for you, subject to availability.''','call conversion, ready, confirm'),
  ('Qualification — Investment vs Personal Use','Client Qualification','Ask early: ''Is this primarily an investment, or somewhere you plan to live?'' Investment buyers care about yield, payment plan, exit and tenant demand; end-users care about layout, community, schools and lifestyle. The answer changes everything you recommend — never pitch before you know it.','qualification, investment, personal use, purpose'),
  ('Qualification — Golden Visa Need','Client Qualification','Ask: ''Is UAE residency or the Golden Visa part of your goal?'' If yes, steer toward property at or above the AED 2M threshold, subject to current rules and authority approval. Position the visa as a potential benefit of qualifying property, never as a guaranteed outcome.','qualification, golden visa, residency, aed 2 million'),
  ('Qualification — Budget','Client Qualification','Ask for a range, not an exact figure: ''What budget range are you working with — for example 1–1.5M, 1.5–3M, or 3M+?'' A range removes pressure and lets you shortlist correctly. Confirm whether the budget is cash, payment-plan-driven, or mortgage-based.','qualification, budget, range, payment'),
  ('Qualification — Property Type','Client Qualification','Confirm the asset: apartment, townhouse, villa, penthouse or commercial. Then bedrooms and must-haves (view, layout, furnished). Type plus budget narrows the market fast and stops you sending irrelevant options.','qualification, property type, apartment, villa, bedrooms'),
  ('Qualification — Timeline','Client Qualification','Ask: ''Are you looking to decide in the next few weeks, or exploring for later?'' Near-term buyers get availability-focused options and a fast next step; longer-horizon buyers get education plus a structured follow-up. Match urgency to their timeline, don''t fake it.','qualification, timeline, urgency, decision'),
  ('Qualification — Rental Income vs Capital Appreciation','Client Qualification','Ask which matters more: steady rental income or long-term capital growth. Income-focused buyers favour ready, high-demand rental areas; growth-focused buyers consider off-plan in emerging or master-planned locations. Discuss both in general terms only — never promise a specific return.','qualification, rental income, capital appreciation, yield'),
  ('Qualification — Ready vs Off-Plan','Client Qualification','Ask: ''Do you prefer something ready to use or rent now, or are you open to off-plan with a payment plan?'' Ready suits immediate use/income and mortgage buyers; off-plan suits staged payments and entry pricing. Present both honestly based on their goal.','qualification, ready, off-plan, payment plan'),
  ('Qualification — Luxury Buyer','Client Qualification','For high-budget clients, qualify on priorities: privacy, prime views, branded residence, developer prestige, finishing quality and long-term resale appeal. Luxury buyers value scarcity and discretion — keep the conversation consultative and unhurried.','qualification, luxury, high net worth, scarcity, prestige'),
  ('Qualification — Overseas Buyer','Client Qualification','For overseas clients, confirm budget, goal, Golden Visa interest, and whether they can travel or need a remote process. Explain that buying remotely is common, outline the steps simply, and offer a Zoom walkthrough and video tours. Flag fees that need verification before any commitment.','qualification, overseas buyer, remote, international, zoom'),
  ('Objection — ''I Am Just Checking''','Objection Handling','Reply: ''That''s completely fine — most smart buyers start by exploring. Let me make your research efficient: a quick sense of your budget and goal and I''ll show you what''s genuinely worth watching, not everything.'' Why it works: removes pressure, repositions you as a guide. Next action: soft-qualify, then offer a short call.','objection, just checking, browsing, soft'),
  ('Objection — ''Dubai Prices Are Too High''','Objection Handling','Reply: ''Prices have moved, that''s true — but Dubai still offers strong rental demand, no annual property tax and entry points other global cities can''t match. The real question is value for your goal, not headline price. Let me show options that make sense at your budget.'' Why it works: reframes price as value. Next action: shortlist by budget.','objection, prices high, expensive, value, dubai market'),
  ('Objection — ''I Want To Wait''','Objection Handling','Reply: ''Waiting can be the right call — let''s just make sure you''re waiting with information, not guessing. I''ll keep you updated on the right launches and price movements so when you''re ready, you act with an edge.'' Why it works: respects the decision, keeps you in the loop. Next action: set a structured follow-up.','objection, want to wait, timing, follow-up'),
  ('Objection — ''Regional Conflict Makes Me Worried''','Objection Handling','Reply: ''I understand the caution. Dubai has historically been viewed as a safe, stable hub, and demand has stayed resilient — but I''d never dismiss your concern. Let''s focus on quality assets in strong locations that hold value through cycles, and you decide at your pace.'' Why it works: acknowledges, doesn''t dismiss, no false promises. Next action: discuss resilient communities.','objection, regional conflict, geopolitics, safety, stability'),
  ('Objection — ''Is Dubai A Bubble?''','Objection Handling','Reply: ''A fair question. Today''s market has more end-user demand, stricter regulation and an escrow system protecting buyers, which is different from past cycles. No market only goes up, so selection matters — right developer, location and price. Let me show you assets chosen for durability, not hype.'' Why it works: balanced, credible. Next action: compare quality options.','objection, bubble, crash, market, regulation'),
  ('Objection — ''Dubai vs London or Europe''','Objection Handling','Reply: ''Both have merits. Versus London or Europe, Dubai typically offers higher gross rental yields, no annual property tax and no personal income tax, plus residency options — while Europe offers maturity and familiarity. For income and tax efficiency, Dubai is hard to beat. Shall I show a like-for-like comparison at your budget?'' Why it works: respectful, fact-based. Next action: comparison call.','objection, london, europe, comparison, yield, tax'),
  ('Objection — ''I Have Another Agent''','Objection Handling','Reply: ''No problem at all — and I won''t step on anyone''s toes. Think of me as a second opinion with strong developer access. If I can add value or surface a better-fit unit, great; if not, you''ve lost nothing.'' Why it works: non-confrontational, value-led. Next action: offer a focused comparison.','objection, another agent, loyalty, second opinion'),
  ('Objection — ''Another Agent Offered A Discount''','Objection Handling','Reply: ''Developer pricing and payment plans are generally standardised, so be a little careful with discount claims — sometimes it''s a fee shift, not real savings. I''ll be transparent on the full cost. Send me what they offered and I''ll give you an honest read.'' Why it works: protects the client, builds trust. Next action: review the offer.','objection, discount, another agent, transparency, fees'),
  ('Objection — ''Can You Get Me A Discount?''','Objection Handling','Reply: ''I''ll always push for the best available terms and any genuine incentives the developer is running — but I won''t promise a discount that doesn''t exist. What I can do is make sure you get the right unit, the best payment plan and full cost transparency.'' Why it works: honest, still helpful. Next action: identify real incentives, subject to developer confirmation.','objection, discount, incentive, payment plan, honesty'),
  ('Objection — Interested But Delaying','Objection Handling','Reply: ''I can tell this fits — and there''s no rush from me. Let''s just protect your position: I''ll flag if the unit or price moves so you decide with full information, not under pressure.'' Why it works: keeps momentum without pushing. Next action: agree a check-in date and watch the unit.','objection, delay, interested, momentum, follow-up'),
  ('Objection — Likes Project But Hesitates','Objection Handling','Reply: ''You clearly like it — let''s pin down the hesitation. Is it budget, payment plan, timing, or comparing with another option? Once I know the real concern, I can solve it properly instead of guessing.'' Why it works: surfaces the true objection. Next action: address the specific concern, then next step.','objection, hesitate, likes project, concern'),
  ('Objection — ''Is ROI Guaranteed?''','Objection Handling','Reply: ''I''d never guarantee ROI — anyone who does isn''t being straight with you. What I can do is show historical performance for comparable assets and the demand drivers, so you make an informed decision. Returns depend on market conditions.'' Why it works: compliant and credible. Next action: share general data with a verification note.','objection, roi guaranteed, returns, compliance'),
  ('Objection — ''What Are The Risks?''','Objection Handling','Reply: ''Good question — every investment has risk. For off-plan it''s developer delivery, market timing and liquidity; for ready it''s price, service charges and resale demand. We reduce risk by choosing strong developers, prime locations and the right payment plan. Let me walk you through it for a specific option.'' Why it works: honest, expert. Next action: risk review on a shortlisted unit.','objection, risks, off-plan, ready, due diligence'),
  ('Off-Plan — What Is Off-Plan Property','Off-Plan Sales Knowledge','Off-plan means buying directly from the developer before or during construction, usually on a staged payment plan, with handover at completion. It can offer entry pricing and flexible payments, but the right developer, location, unit and price matter more than simply buying early.','off-plan, definition, developer, payment plan, handover'),
  ('Off-Plan — Benefits','Off-Plan Sales Knowledge','Potential benefits: lower entry price than completed stock, staged payment plans that ease cash flow, modern layouts and amenities, and a window for capital growth during construction in strong locations. None of these are guaranteed — they depend on selection and market conditions.','off-plan, benefits, entry price, payment plan, growth'),
  ('Off-Plan — Risks','Off-Plan Sales Knowledge','Key risks: construction or handover delays, market movement before completion, and lower short-term liquidity. Mitigate by choosing reputable developers with escrow-protected projects, prime locations and sensible payment plans. Always set realistic expectations with the client.','off-plan, risks, delays, liquidity, escrow'),
  ('Off-Plan — How To Evaluate','Off-Plan Sales Knowledge','Evaluate on: developer track record and delivery history, location and master-plan, unit type and layout, payment plan structure, price versus comparable launches, and expected demand at handover. Off-plan can be strong when selected properly — never imply every off-plan project is good.','off-plan, evaluate, developer, location, payment plan, price'),
  ('Off-Plan — Can I Sell Before Handover?','Off-Plan Sales Knowledge','Often yes, via assignment/resale once a developer-set percentage is paid — rules and transfer fees vary by developer and project, subject to developer confirmation. It''s a common exit, but confirm the specific project''s resale terms before promising anything.','off-plan, resale, assignment, exit, before handover'),
  ('Off-Plan — Is Off-Plan Safe?','Off-Plan Sales Knowledge','Dubai off-plan is regulated, with buyer payments typically held in escrow and released against construction milestones. That structure adds protection, but safety still comes from choosing the right developer, project and price. Use ''subject to'' language and avoid blanket reassurances.','off-plan, safe, escrow, regulation, rera'),
  ('Off-Plan — How Much Do I Need To Start?','Off-Plan Sales Knowledge','Entry usually starts with a booking/down payment (commonly around 10–20% of price, varies by developer and project), then staged instalments. Plus DLD and registration fees. Exact figures are project-specific and must be verified with the developer before confirming to a client.','off-plan, down payment, booking amount, dld, costs'),
  ('Off-Plan — Extra Costs','Off-Plan Sales Knowledge','Beyond the unit price, budget for the DLD registration fee, Oqood/registration charges, any admin fees, and (where applicable) agency and service charges at handover. Always present the full cost picture so there are no surprises — verify current figures before quoting.','off-plan, extra costs, dld, oqood, service charges, fees'),
  ('Ready Property — What Is Ready Property','Ready Property Knowledge','Ready property is a completed, handed-over unit you can use, rent or resell immediately. It suits buyers who want instant use or income. Always compare current market price, rental value, service charges, condition and resale demand before proceeding.','ready property, completed, immediate, rental, resale'),
  ('Ready Property — For Rental Income','Ready Property Knowledge','For income, prioritise high-demand rental locations, healthy gross yields, manageable service charges and tenant-friendly layouts. Ready stock generates rent from day one. Discuss yields in general terms and verify current rental rates before quoting.','ready property, rental income, yield, tenant demand'),
  ('Ready Property — For Personal Use','Ready Property Knowledge','For end-users, focus on community, layout, finishing, amenities, schools and commute rather than pure investment metrics. Ready lets them move in immediately and inspect the actual unit before buying.','ready property, personal use, end user, lifestyle, community'),
  ('Ready Property — For Mortgage Buyers','Ready Property Knowledge','Ready property is generally more straightforward for mortgages than off-plan. Confirm down-payment requirements, eligibility and rates with a mortgage advisor or bank — these vary and must be verified. Position financing as a tool, not a guarantee.','ready property, mortgage, finance, down payment, bank'),
  ('Ready Property — For Lower Construction Risk','Ready Property Knowledge','Buyers worried about delivery risk prefer ready: no construction or handover uncertainty, and what you see is what you get. The trade-off is usually a higher entry price than off-plan. Present both sides honestly.','ready property, construction risk, delivery, completed'),
  ('Ready Property — And Golden Visa Planning','Ready Property Knowledge','Ready property at or above the AED 2M threshold can support a Golden Visa application, subject to current rules and authority approval. The advantage is an existing, valued asset. Never guarantee visa approval — final decision rests with the authority.','ready property, golden visa, aed 2 million, residency'),
  ('Luxury — How To Evaluate Luxury Property','Luxury Property Knowledge','For luxury, the strongest assets usually combine scarcity, prime views, top developer reputation, privacy and long-term resale appeal. Square-foot price matters less than uniqueness and demand for that specific address. Keep the conversation consultative and discreet.','luxury, evaluate, scarcity, prime view, prestige'),
  ('Luxury — Buyer Priorities','Luxury Property Knowledge','Luxury buyers prioritise privacy, exclusivity, finishing quality, branded-residence services, views and a trophy address. Price sensitivity is lower; fit, discretion and prestige are higher. Sell the lifestyle and rarity, not the discount.','luxury, buyer priorities, privacy, branded, lifestyle'),
  ('Luxury — Scarcity Drives Value','Luxury Property Knowledge','In luxury, limited supply protects value: waterfront plots, penthouses, signature villas and branded residences are inherently scarce. Position scarcity honestly — ''limited availability, subject to confirmation'' — never manufacture false urgency.','luxury, scarcity, waterfront, penthouse, value'),
  ('Luxury — Waterfront, Branded, Penthouse, Villa Positioning','Luxury Property Knowledge','Waterfront and beachfront command premiums for views and lifestyle; branded residences add service and resale prestige; penthouses offer rarity and skyline views; signature villas offer privacy and land. Match the asset type to the buyer''s priority and resale horizon.','luxury, waterfront, branded residence, penthouse, villa'),
  ('Villas — Demand in Dubai','Villa and Townhouse Knowledge','Family demand for villas in Dubai has remained strong, and quality villa inventory is more limited than apartment supply. Well-located villas in established communities can perform well for both lifestyle and resale. Confirm current pricing and availability before quoting.','villa, demand, family, inventory, dubai'),
  ('Townhouses — Demand in Dubai','Villa and Townhouse Knowledge','Townhouses bridge apartments and villas — more space and privacy than a flat, at a lower entry than a standalone villa. They appeal strongly to growing families and first-time villa buyers in master-planned communities.','townhouse, demand, family, master plan, value'),
  ('Villas — Family Buyer Logic','Villa and Townhouse Knowledge','Family buyers weigh schools, safety, community amenities, layout, garden/plot and commute over pure yield. Lead with lifestyle fit and long-term suitability; the investment case supports the decision but rarely drives it for end-users.','villa, family buyer, schools, lifestyle, community'),
  ('Villas — Selection Criteria','Villa and Townhouse Knowledge','Assess plot size, built-up area, layout efficiency, privacy, view, community quality, school proximity and developer. A larger plot in a strong community usually protects resale value better than a bigger build on a weak plot.','villa, selection, plot size, bua, layout, privacy'),
  ('Villas — Plot, BUA, Layout, Privacy, Schools','Villa and Townhouse Knowledge','Five villa value drivers: plot size (land you own), BUA (livable area), layout (flow and usability), privacy (corner/back-to-back), and school access (catchment demand). Strong scores here support both lifestyle and resale.','villa, plot, bua, layout, privacy, schools'),
  ('Holiday Homes — Investment Overview','Holiday Home Knowledge','Not every property suits holiday-home (short-term rental) use. Before recommending it, check building/community rules, location demand, furnishing needs, expected occupancy, daily rate and management cost. Done right in the right building, it can outperform long-term rent — but it''s not universal.','holiday home, short term rental, investment, occupancy'),
  ('Holiday Homes — Short-Term Rental Suitability','Holiday Home Knowledge','Best suited to tourist-heavy, high-footfall locations near beaches, Downtown, Marina and key attractions. Suitability depends on the specific building''s permissions and demand patterns. Always verify the building allows short-term letting before advising the client.','holiday home, short term, suitability, location, tourism'),
  ('Holiday Homes — Building Rules','Holiday Home Knowledge','Some buildings and communities restrict or prohibit short-term letting, and a DTCM/holiday-home permit is typically required. Confirm the building''s rules and permit eligibility before positioning a unit as a holiday home — subject to authority approval.','holiday home, building rules, dtcm, permit, regulation'),
  ('Holiday Homes — Occupancy, Daily Rate, Management Cost','Holiday Home Knowledge','The economics hinge on occupancy rate, achievable daily rate (seasonal), and operator/management fees (cleaning, listings, guest handling). Model conservatively and present net, not gross. Verify current rates with an operator before sharing projections.','holiday home, occupancy, daily rate, management, net yield'),
  ('Dubai Market — Why Dubai','Dubai Market Knowledge','Dubai offers no annual property tax, no capital gains tax and no personal income tax, strong rental demand, high safety, world-class infrastructure, global connectivity and residency options including the Golden Visa. It''s a tax-efficient, lifestyle-rich market — but never guarantee future price growth.','dubai market, why dubai, tax free, safety, golden visa'),
  ('Dubai Market — 2040 Urban Master Plan','Dubai Market Knowledge','The Dubai 2040 Urban Master Plan guides long-term growth: more green space, expanded communities, transport and a higher quality of life for a growing population. It signals sustained investment and planning, which supports long-term demand — frame it as context, not a price promise.','dubai market, 2040 master plan, growth, infrastructure'),
  ('Dubai Market — Rental Yields','Dubai Market Knowledge','Dubai has historically offered attractive gross rental yields compared with many global cities, varying by area and property type. Quote yields in general terms and verify current rents for a specific unit before sharing numbers with a client.','dubai market, rental yield, income, returns'),
  ('Dubai Market — Capital Appreciation','Dubai Market Knowledge','Prime and master-planned areas have seen capital growth over time, but markets move in cycles and past performance is not a promise. Position appreciation as a possibility driven by location, demand and selection — never as a guarantee.','dubai market, capital appreciation, growth, cycles'),
  ('Dubai Market — Tax Benefits','Dubai Market Knowledge','Key tax advantages: no annual property tax, no capital gains tax on property, and no personal income tax. This materially improves net returns versus high-tax markets. (A one-time DLD transfer fee and standard fees still apply — verify current figures.)','dubai market, tax benefits, no income tax, no capital gains'),
  ('Dubai Market — Dubai vs London / Europe','Dubai Market Knowledge','Versus London or Europe, Dubai typically offers higher gross yields, no annual property or income tax, faster transactions and residency options; Europe offers market maturity and familiarity. For income and tax efficiency, Dubai is compelling. Offer a like-for-like comparison.','dubai market, vs london, vs europe, comparison, yield'),
  ('Dubai Market — Safety and Stability','Dubai Market Knowledge','Dubai is widely regarded as one of the safest cities globally, with strong governance and a stable, business-friendly environment. This underpins investor and end-user confidence. State it factually and avoid political commentary.','dubai market, safety, stability, governance'),
  ('Dubai Market — Global City Status','Dubai Market Knowledge','Dubai is a global hub for business, tourism, aviation and finance, with growing population and tourism, modern infrastructure and long-term residency options. These fundamentals support sustained property demand across cycles.','dubai market, global city, tourism, business hub, connectivity'),
  ('Golden Visa — Overview','Golden Visa Knowledge','The UAE Golden Visa is a long-term renewable residency. Property investment can help you qualify, generally with property ownership of AED 2 million or more, subject to current rules and authority approval. Always position it as a potential benefit, never a guaranteed outcome.','golden visa, overview, residency, aed 2 million'),
  ('Golden Visa — Property Investor Route','Golden Visa Knowledge','Buying qualifying property (generally AED 2M+) can support a property-investor Golden Visa application, subject to authority approval. We guide clients to suitable qualifying properties; final eligibility and approval always rest with the government authority.','golden visa, property investor, qualify, threshold'),
  ('Golden Visa — AED 2 Million Threshold','Golden Visa Knowledge','The commonly referenced property threshold is AED 2 million, applicable to ready and, in many cases, off-plan purchases, subject to current rules. Confirm the latest threshold and conditions with the authority before advising — rules can change.','golden visa, aed 2 million, threshold, eligibility'),
  ('Golden Visa — Off-Plan and Golden Visa','Golden Visa Knowledge','Off-plan purchases at or above the threshold can, in many cases, count toward the Golden Visa, subject to developer and authority confirmation and any minimum-payment conditions. Verify the specific project and current rules before promising eligibility.','golden visa, off-plan, qualify, authority approval'),
  ('Golden Visa — Golden-Visa-Only Client','Golden Visa Knowledge','If the client''s main goal is the visa, recommend a clean qualifying asset that also makes investment sense (rentable, good location, resaleable). Don''t let the visa goal push them into a weak property — the asset still has to stand on its own.','golden visa, visa only client, qualifying asset, advice'),
  ('Golden Visa — Documents','Golden Visa Knowledge','Typically required: passport copy, photo, proof of property ownership/title, and supporting financial documents — exact list varies and is confirmed by the authority or a processing agent. Share as a guide and tell the client the authority confirms final requirements.','golden visa, documents, passport, title deed, checklist'),
  ('Golden Visa — Client Script','Golden Visa Knowledge','''Property investment can help you qualify for the UAE Golden Visa if the value meets the required threshold, generally AED 2 million or more, subject to authority approval. I''ll guide you to suitable properties, but final visa approval always comes from the government authority.''','golden visa, client script, whatsapp, compliant'),
  ('Golden Visa — Do-Not-Say Rules','Golden Visa Knowledge','Never say the visa is ''guaranteed'', ''approved'', ''automatic'' or ''instant''. Never promise a timeline or override authority decisions. Always use ''subject to authority approval'' and direct final eligibility to the official authority.','golden visa, do not say, compliance, never guarantee'),
  ('Developers — How To Compare Developers','Developer Knowledge','Compare on delivery track record, build and finishing quality, location of projects, payment-plan flexibility, after-sales/handover experience and resale demand. No developer is always best — evaluate project by project for the client''s specific goal.','developer, compare, track record, quality, project by project'),
  ('Developer — Emaar','Developer Knowledge','Emaar is a leading master-developer known for landmark communities (Downtown, Dubai Hills, Dubai Creek Harbour, Emaar South) and strong delivery and resale demand. Often suits investors and end-users wanting blue-chip locations. Still assess each specific project and unit.','developer, emaar, downtown, dubai hills, blue chip'),
  ('Developer — Meraas','Developer Knowledge','Meraas is known for premium, design-led, lifestyle destinations (e.g. City Walk, Bluewaters, Jumeirah) with a boutique, high-quality positioning. Often suits buyers wanting distinctive, lifestyle-rich addresses. Evaluate project specifics and pricing.','developer, meraas, city walk, bluewaters, lifestyle, premium'),
  ('Developer — Nakheel','Developer Knowledge','Nakheel is behind iconic waterfront and master communities (Palm Jumeirah, Palm Jebel Ali, and more), strong on waterfront and large-scale lifestyle. Often suits buyers seeking beach/waterfront and landmark addresses. Confirm project-level details.','developer, nakheel, palm jumeirah, palm jebel ali, waterfront'),
  ('Developer — DAMAC','Developer Knowledge','DAMAC is a major private developer with a wide range from accessible to branded-luxury projects and frequent launches. Quality and location vary by project, so selection matters — assess each launch on its own merits for the client''s goal.','developer, damac, branded, luxury, launches'),
  ('Developer — Sobha','Developer Knowledge','Sobha is known for in-house construction and high build quality, with flagship communities like Sobha Hartland. Often suits quality-focused buyers. Verify project specifics, payment plan and pricing for the recommendation.','developer, sobha, hartland, build quality'),
  ('Developer — Binghatti','Developer Knowledge','Binghatti is known for distinctive design and fast-moving launches, often at accessible entry points and increasingly in branded collaborations. Suits buyers wanting design-led, entry-to-mid pricing — assess location and delivery per project.','developer, binghatti, design, branded, entry price'),
  ('Developer — Ellington','Developer Knowledge','Ellington is a design-focused boutique developer known for refined, contemporary residences and quality finishing. Often suits buyers prioritising design and end-user living. Evaluate each project''s location and pricing.','developer, ellington, boutique, design, quality'),
  ('Developer — Omniyat','Developer Knowledge','Omniyat is known for ultra-luxury, architecturally significant and branded developments (e.g. on the Dubai Water Canal and Palm). Suits high-net-worth buyers seeking trophy assets. Position on scarcity and prestige; confirm specifics.','developer, omniyat, ultra luxury, branded, trophy'),
  ('Communities — How To Recommend Areas','Community Knowledge','Recommend areas by fit, not favouritism: weigh budget, purpose, property type, timeline, lifestyle, school needs, Golden Visa goal, rental/resale aim and risk appetite. The right area for one client is wrong for another — always tie the suggestion to their stated goal.','community, recommend areas, fit, budget, purpose'),
  ('Community — Dubai Hills Estate','Community Knowledge','Dubai Hills Estate (Emaar) is a premium master community with villas, townhouses and apartments, a central park, golf and a major mall. Popular with families and investors for lifestyle and resale demand. Confirm current pricing and availability.','community, dubai hills estate, emaar, family, villas, golf'),
  ('Community — Dubai Creek Harbour','Community Knowledge','Dubai Creek Harbour (Emaar) is a waterfront master-plan with modern apartments, marina and creek views, near Downtown. Appeals to investors and end-users wanting new waterfront living with growth potential. Verify project specifics.','community, dubai creek harbour, emaar, waterfront, apartments'),
  ('Community — Emaar South','Community Knowledge','Emaar South is a master community near Al Maktoum Airport and Expo City, offering villas, townhouses and apartments at relatively accessible entry points. Suits value-focused and longer-horizon buyers. Confirm current pricing.','community, emaar south, expo, value, villas, townhouses'),
  ('Community — Palm Jebel Ali','Community Knowledge','Palm Jebel Ali (Nakheel) is a large new waterfront/island master-development positioned for premium beachfront living and long-term growth. Appeals to investors seeking next-generation waterfront. Details and availability subject to developer confirmation.','community, palm jebel ali, nakheel, waterfront, beachfront'),
  ('Community — Business Bay','Community Knowledge','Business Bay is a central, mixed-use district along the Water Canal with apartments, offices and hotels, near Downtown. Strong for rental demand and short-term-let potential (subject to building rules). Suits investors wanting central, liquid stock.','community, business bay, central, apartments, rental, canal'),
  ('Community — Dubai Marina','Community Knowledge','Dubai Marina is a mature, high-demand waterfront district with strong rental and short-term-let appeal (subject to building rules), lifestyle and walkability. A reliable income location for investors. Verify current rents and rules.','community, dubai marina, waterfront, rental, lifestyle'),
  ('Community — JVC (Jumeirah Village Circle)','Community Knowledge','JVC is a popular, value-oriented community with apartments, townhouses and villas, often offering attractive entry prices and yields. Suits first-time investors and value buyers. Confirm building quality and current pricing per project.','community, jvc, jumeirah village circle, value, yield, apartments'),
  ('Community — Downtown Dubai','Community Knowledge','Downtown Dubai (Emaar) is the iconic centre — Burj Khalifa, Dubai Mall, premium apartments — with strong global demand, prestige and short-term-let appeal (subject to rules). Suits prestige-seeking and income investors. Verify pricing and availability.','community, downtown dubai, burj khalifa, prestige, apartments'),
  ('Follow-Up — After Sending Brochure','Follow-Up Scripts','''Hi [Name], did you get a chance to look through the brochure I sent? Happy to walk you through the key points in 5 minutes and answer anything — what works for a quick call?''','follow-up, after brochure, whatsapp, call'),
  ('Follow-Up — After Sending Price List','Follow-Up Scripts','''Hi [Name], following up on the pricing I shared. Prices and availability can move, so if any option stood out, let''s lock the details before they change — shall I check current availability for you?''','follow-up, after price list, availability, urgency'),
  ('Follow-Up — After Sending Multiple Options','Follow-Up Scripts','''Hi [Name], of the options I sent, which one felt closest to what you''re after? Even a quick reaction helps me narrow it down and send you the single best fit.''','follow-up, multiple options, shortlist, narrow'),
  ('Follow-Up — No Response (Follow-Up 1)','Follow-Up Scripts','''Hi [Name], just circling back on your Dubai property search. Still happy to help whenever the timing''s right — anything you''d like me to send or clarify?''','follow-up, no response, first, gentle'),
  ('Follow-Up — No Response (Follow-Up 2)','Follow-Up Scripts','''Hi [Name], I don''t want to crowd your inbox — should I keep you updated on strong new launches that match your budget, or is now not the right time? Either answer is fine.''','follow-up, no response, second, opt-in'),
  ('Follow-Up — No Response (Follow-Up 3)','Follow-Up Scripts','''Hi [Name], last note from me for now. I''ll be here when you''re ready, and I''ll keep an eye out for anything that fits your goal. Wishing you well — just message anytime.''','follow-up, no response, third, graceful'),
  ('Follow-Up — Interested But Delaying','Follow-Up Scripts','''Hi [Name], no rush at all — I just want to protect your position. If the unit or price you liked starts to move, I''ll flag it so you decide with full information. Shall I keep watching it for you?''','follow-up, delaying, interested, watch unit'),
  ('Follow-Up — Likes Project But Hesitates','Follow-Up Scripts','''Hi [Name], you liked [project] — is the hold-up budget, payment plan, timing, or comparing options? Tell me the real concern and I''ll solve it properly so you can decide with confidence.''','follow-up, hesitates, concern, project'),
  ('Meeting — Client Ready For Meeting','Meeting and Site Visit Scripts','''Great — let''s meet properly so I can tailor everything to you. Would you prefer our office, a Zoom call, or to view on site? I''ll prepare a focused shortlist for your budget and goal either way.''','meeting, ready, office, zoom, site visit'),
  ('Meeting — Office Meeting Invitation','Meeting and Site Visit Scripts','''Hi [Name], let''s sit down at our Amber Homes office so I can show you options properly and answer everything in one go. What day and time suit you this week?''','meeting, office, invitation, schedule'),
  ('Meeting — Zoom Meeting Invitation','Meeting and Site Visit Scripts','''Hi [Name], a quick Zoom is perfect if you''re remote — I''ll share my screen, walk you through shortlisted projects and pricing, and answer live. Does [suggest time] work? I''ll send the link.''','meeting, zoom, remote, invitation, overseas'),
  ('Site Visit — Invitation','Meeting and Site Visit Scripts','''Hi [Name], the best way to feel a project is to see it. I can arrange a site visit or show flat and a quick community tour so you experience the location first-hand. Which day works for you?''','site visit, invitation, show flat, community tour'),
  ('Site Visit — Confirmation','Meeting and Site Visit Scripts','''Confirmed, [Name] — site visit on [day/time] at [location]. I''ll meet you there and bring the unit details and pricing. If anything changes, just message me. Looking forward to it.''','site visit, confirmation, schedule'),
  ('Site Visit — After Site Visit','Meeting and Site Visit Scripts','''Hi [Name], great to show you [project] today. What were your first impressions? If it felt right, the next step is to check current availability and secure your preferred unit before it moves — shall I do that?''','site visit, after visit, next step, secure unit'),
  ('EOI — Client Ready For EOI','EOI and Booking Process','''Perfect — to register your interest and hold priority on your preferred unit, we submit an EOI (Expression of Interest) with a refundable/structured deposit, subject to developer terms. I''ll guide you through it. Shall I start the EOI for your selected unit?''','eoi, expression of interest, ready, priority, deposit'),
  ('EOI — Document Checklist','EOI and Booking Process','Typically for an EOI: passport copy, full name as per passport, email, mobile number, nationality, preferred unit type and budget range, plus the EOI deposit per developer terms. Confirm the exact list for the specific developer before collecting.','eoi, documents, passport, checklist, deposit'),
  ('Booking — Client Ready To Book','EOI and Booking Process','''Excellent decision — to book, we complete the booking form and pay the booking amount to secure the unit, subject to availability and developer confirmation. I''ll prepare everything and walk you through each step. Ready to proceed?''','booking, ready to book, booking amount, secure unit'),
  ('Booking — Document Checklist','EOI and Booking Process','Typically for booking: passport copy, full name as per passport, contact details, nationality, buyer type, proof of payment for the booking amount, and the signed booking form — subject to the developer''s requirements. Verify the exact checklist per developer.','booking, documents, passport, payment proof, checklist'),
  ('Booking — After Booking','EOI and Booking Process','''Congratulations [Name]! Your unit is booked, subject to developer confirmation. Next, you''ll receive the SPA and the payment schedule. I''ll stay with you through every step — registration, payments and handover. Welcome to your Dubai investment.''','booking, after booking, spa, payment schedule, next steps'),
  ('Booking — Next Steps After Booking','EOI and Booking Process','After booking: SPA signing, DLD/Oqood registration, then payment-plan instalments through to handover. Keep the client informed at each milestone and set reminders for due payments. Confirm fees and dates with the developer/DLD.','booking, next steps, spa, registration, payments, handover'),
  ('Closing — Smart Closing Language','Closing Language','''I''d never push you into something that doesn''t make sense. But if the project, price, unit and payment plan match your objective, the next step is simply to secure availability before it changes.'' Calm, advisory, and respects the client — this is the Amber Homes close.','closing, smart close, advisory, next step'),
  ('Closing — Soft Close','Closing Language','''Based on everything you''ve told me, [unit] fits your goal well. How are you feeling about moving forward? If it''s right, I''ll handle the next step for you.'' Low-pressure, invites the decision.','closing, soft close, feeling, decision'),
  ('Closing — Availability Close','Closing Language','''This unit/price is attracting interest and availability can change quickly, subject to confirmation. If it''s the right fit, securing it now protects your position — shall I check live availability and hold it for you?'' Use only when genuinely true.','closing, availability close, urgency, secure'),
  ('Closing — Comparison Close','Closing Language','''You''ve now seen the options side by side. For your goal, [unit] gives you the best balance of price, location and payment plan. Shall we move on that one?'' Helps the client decide by clarifying the best fit.','closing, comparison close, options, best fit'),
  ('Closing — Next-Step Close','Closing Language','''Great — the next step is simple: I''ll confirm current availability, share the booking details, and guide you through securing it. Shall I get that started for you now?'' Turns agreement into action.','closing, next step close, action, booking'),
  ('Compliance — Do Not Guarantee ROI','Compliance and Do-Not-Say Rules','Never guarantee ROI, rental returns or capital appreciation. Use general, historical or comparable framing with a verification note. Correct: ''returns depend on market conditions; here''s how comparable assets have performed.'' This protects the client and Amber Homes.','compliance, do not say, roi, returns, guarantee'),
  ('Compliance — Do Not Guarantee Golden Visa','Compliance and Do-Not-Say Rules','Never guarantee Golden Visa eligibility, approval or timelines. Position property as potentially qualifying, generally AED 2M+, subject to authority approval, with final decision by the official authority.','compliance, do not say, golden visa, approval'),
  ('Compliance — Do Not Guarantee Availability','Compliance and Do-Not-Say Rules','Never state a specific unit is definitely available. Use ''subject to availability'' and offer to check live status before any commitment. Availability changes constantly and must be verified with the developer.','compliance, do not say, availability, subject to'),
  ('Compliance — Do Not Guarantee Allocation','Compliance and Do-Not-Say Rules','Never promise a specific unit, floor, view or allocation before it is confirmed by the developer. Use ''subject to developer confirmation''. Manage expectations honestly to avoid disappointment and reputational risk.','compliance, do not say, allocation, unit, developer confirmation'),
  ('Compliance — Do Not Guarantee Discounts','Compliance and Do-Not-Say Rules','Never promise discounts that don''t exist. You may mention genuine, developer-confirmed incentives, framed as ''subject to developer confirmation''. Transparency on price and fees builds trust and protects credibility.','compliance, do not say, discount, incentive'),
  ('Compliance — Use ''Subject To'' Language','Compliance and Do-Not-Say Rules','Default to protective wording on anything unconfirmed: ''subject to availability'', ''subject to developer confirmation'', ''subject to authority approval'', ''based on current market information''. It keeps every message compliant and credible.','compliance, subject to, safe language, wording'),
  ('Compliance — Avoid Fake Promises','Compliance and Do-Not-Say Rules','Do not invent prices, payment plans, sizes, handover dates, fees, awards, rankings or ''sold out/available'' status. If a fact isn''t verified, say it needs verification. Honesty is the brand — never fabricate to win a reply.','compliance, fake promises, never invent, honesty'),
  ('Compliance — Avoid Over-Selling','Compliance and Do-Not-Say Rules','Don''t oversell or pressure. Calm, advisory confidence converts better in the premium segment than hype. Recommend by fit and let the client decide — pushiness erodes trust and resale relationships.','compliance, over-selling, pressure, advisory'),
  ('Compliance — Protect Amber Homes Credibility','Compliance and Do-Not-Say Rules','Every message represents Amber Homes. Stay accurate, premium and compliant. When unsure, verify before confirming. Protecting credibility and the long-term client relationship always outweighs closing one deal faster.','compliance, credibility, brand, trust, reputation'),
  ('System — Response Style (Short, Premium, Practical)','Master Prompt / AI System Behavior','Default outputs are short, premium, practical and sales-focused with a clear next step. For WhatsApp drafts, give ONLY the ready-to-send message unless the agent asks for explanation. For training, give concise bullets. For objections, give the recommended reply, why it works, and the next action.','system, response style, short, premium, whatsapp draft'),
  ('System — Always Move To The Next Commercial Step','Master Prompt / AI System Behavior','Whatever the question, end by advancing the deal: a call, Zoom, office meeting, site visit, presentation, shortlist, EOI, booking, follow-up or close. Be calm and advisory — recommend the next step, never pressure it.','system, next step, commercial, advisory, close')
) as v(title, category, content, tags)
where not exists (select 1 from public.ai_knowledge k where k.title = v.title);

